import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { resolve } from "node:path";

const TODOS_FILE = resolve(process.cwd(), "todos.json");

function readTodos(): string[] {
  if (!existsSync(TODOS_FILE)) return [];
  try {
    const data = JSON.parse(readFileSync(TODOS_FILE, "utf8"));
    return Array.isArray(data) ? data : [];
  } catch {
    return [];
  }
}

function writeTodos(todos: string[]): void {
  writeFileSync(TODOS_FILE, JSON.stringify(todos, null, 2));
}

function main(): void {
  const [command, ...args] = process.argv.slice(2);

  switch (command) {
    case "add": {
      const text = args.join(" ");
      const todos = readTodos();
      todos.push(text);
      writeTodos(todos);
      break;
    }
    case "list": {
      const todos = readTodos();
      for (const todo of todos) {
        console.log(todo);
      }
      break;
    }
    default:
      console.error(`Unknown command: ${command ?? ""}`);
      process.exit(1);
  }
}

main();

